   448→// rangeEvents returns events in range [minRev, maxRev).
   449→func rangeEvents(lg *zap.Logger, b backend.Backend, minRev, maxRev int64) []mvccpb.Event {
   450→	if minRev < 0 {
   451→		lg.Warn("Unexpected negative revision range start", zap.Int64("minRev", minRev))
   452→		minRev = 0
   453→	}
   454→	minBytes, maxBytes := NewRevBytes(), NewRevBytes()
   455→	minBytes = RevToBytes(Revision{Main: minRev}, minBytes)
   456→	maxBytes = RevToBytes(Revision{Main: maxRev}, maxBytes)
   457→
   458→	// UnsafeRange returns keys and values. And in boltdb, keys are revisions.
   459→	// values are actual key-value pairs in backend.
   460→	tx := b.ReadTx()
   461→	tx.RLock()
   462→	revs, vs := tx.UnsafeRange(schema.Key, minBytes, maxBytes, 0)
   463→	evs := kvsToEvents(lg, revs, vs)
   464→	// Must unlock after kvsToEvents, because vs (come from boltdb memory) is not deep copy.
   465→	// We can only unlock after Unmarshal, which will do deep copy.
   466→	// Otherwise we will trigger SIGSEGV during boltdb re-mmap.
   467→	tx.RUnlock()
   468→	return evs
   469→}
